	@Test
	void composesBinaryAlgebraOnlyThroughEstimateMath() {
		RecordingEvidenceSource source = new RecordingEvidenceSource();
		LmdbEstimationEngine engine = new LmdbEstimationEngine(source, new EstimateEvidenceResolver());
		StatementPattern leftPattern = pattern("s", P1, "x");
		StatementPattern rightPattern = pattern("x", P2, "y");
		EstimateContext context = EstimateContext.root(new Join(leftPattern, rightPattern), IDENTITY, 4L);
		BagEstimate left = source.bag(leftPattern);
		BagEstimate right = source.bag(rightPattern);

		assertEquals(EstimateMath.innerJoin(left, right, Set.of("x")).rows(),
				engine.estimate(new Join(leftPattern.clone(), rightPattern.clone()), context).rows());
		assertEquals(EstimateMath.leftJoin(left, right, Set.of("x")).rows(),
				engine.estimate(new LeftJoin(leftPattern.clone(), rightPattern.clone()), context).rows());
		assertEquals(EstimateMath.difference(left, right, Set.of("x")).rows(),
				engine.estimate(new Difference(leftPattern.clone(), rightPattern.clone()), context).rows());
		assertEquals(EstimateMath.union(left, right).rows(),
				engine.estimate(new Union(leftPattern.clone(), rightPattern.clone()), context).rows());
	}

	@Test
	void composesFilterGroupDistinctProjectionAndSliceUniformly() {
		RecordingEvidenceSource source = new RecordingEvidenceSource();
		LmdbEstimationEngine engine = new LmdbEstimationEngine(source, new EstimateEvidenceResolver());
		StatementPattern pattern = pattern("s", P1, "x");
		EstimateContext context = EstimateContext.root(pattern, IDENTITY, 4L);

		Filter filter = new Filter(pattern.clone(), new ValueConstant(VF.createLiteral(true)));
		assertEquals(2.0d, engine.estimate(filter, context).rows());
		assertEquals(2.0d, engine.estimate(new Group(pattern.clone(), Set.of("s")), context).rows());
		assertEquals(EstimateMath.distinct(source.bag(pattern), pattern.getBindingNames()).rows(),
				engine.estimate(new Distinct(pattern.clone()), context).rows());

		ProjectionElemList elements = new ProjectionElemList();
		elements.addElement(new ProjectionElem("s", "subject"));
		BagEstimate projected = engine.estimate(new Projection(pattern.clone(), elements), context);
		assertEquals(Set.of("subject"), projected.variables().keySet());
		assertEquals(3.0d, engine.estimate(new Slice(pattern.clone(), 1L, 3L), context).rows());
	}

	@Test
	void finiteValuesPreserveBagMultiplicityAndEmptySingletonContracts() {
		LmdbEstimationEngine engine = new LmdbEstimationEngine(new RecordingEvidenceSource(),
				new EstimateEvidenceResolver());
		BindingSetAssignment values = new BindingSetAssignment();
		MapBindingSet first = new MapBindingSet();
		first.addBinding("x", VF.createLiteral(1));
		MapBindingSet duplicate = new MapBindingSet();
		duplicate.addBinding("x", VF.createLiteral(1));
		MapBindingSet second = new MapBindingSet();
		second.addBinding("x", VF.createLiteral(2));
		values.setBindingSets(List.of(first, duplicate, second));
		EstimateContext context = EstimateContext.root(values, IDENTITY, 4L);

		BagEstimate estimate = engine.estimate(values, context);

		assertEquals(3.0d, estimate.rows());
		assertEquals(2.0d, estimate.variable("x").distinctRows());
		assertEquals(2.0d, estimate.finiteRelation(Set.of("x")).orElseThrow().frequencies().size());
		assertEquals(0.0d, engine.estimate(new EmptySet(), context).rows());
		assertEquals(1.0d, engine.estimate(new SingletonSet(), context).rows());
	}

	@Test
	void finiteValuesTreatUndefAsUnboundDuringExactJoin() {
		LmdbEstimationEngine engine = new LmdbEstimationEngine(new RecordingEvidenceSource(),
				new EstimateEvidenceResolver());
		BindingSetAssignment undef = new BindingSetAssignment();
		undef.setBindingNames(Set.of("x"));
		undef.setBindingSets(List.of(new MapBindingSet()));
		BindingSetAssignment bound = new BindingSetAssignment();
		MapBindingSet value = new MapBindingSet();
		value.addBinding("x", P1);
		bound.setBindingSets(List.of(value));
		Join join = new Join(undef, bound);
		EstimateContext context = EstimateContext.root(join, IDENTITY, 4L);

		BagEstimate undefEstimate = engine.estimate(undef, context);
		BagEstimate estimate = engine.estimate(join, context);

		assertEquals(1.0d, undefEstimate.rows());
		assertEquals(0.0d, undefEstimate.variable("x").boundRows());
		assertEquals(1.0d, undefEstimate.variable("x").nullableRows());
		assertEquals(1.0d, estimate.rows());
		assertEquals(P1, estimate.finiteRelation(Set.of("x")).orElseThrow().frequencies().keySet()
				.iterator()
				.next()
				.getFirst());
		assertEquals(1.0d, engine.estimate(new LeftJoin(undef.clone(), bound.clone()), context).rows());
		assertEquals(1.0d, engine.estimate(new Difference(undef.clone(), bound.clone()), context).rows());
	}

