	@Test
	void exactLeafProbeRequiresTierAndDecisionPermission() {
		AtomicBoolean exactInvoked = new AtomicBoolean();
		RecordingEvidenceSource source = new RecordingEvidenceSource() {
			@Override
			public Optional<EstimateCandidate> exactCandidate(TupleExpr expression, EstimateContext context) {
				exactInvoked.set(true);
				BagEstimate exact = BagEstimate.exact(7.0d, "exact_storage");
				return Optional.of(new EstimateCandidate(exact,
						new RowEvidence(7.0d, 7.0d, 7.0d, 1.0d, true, IDENTITY, 4L, "exact_storage"),
						EstimateCandidate.Kind.EXACT_STORAGE, 2L));
			}
		};
		LmdbEstimationEngine engine = new LmdbEstimationEngine(source, new EstimateEvidenceResolver());
		StatementPattern pattern = pattern("s", P1, "x");
		EstimateContext root = EstimateContext.root(pattern, IDENTITY, 4L).withExactProbePermission(true);

		engine.estimate(pattern, root);
		assertFalse(exactInvoked.get());

		BagEstimate exact = engine.estimate(pattern,
				root.withEstimationTier(
						org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel.EstimationTier.DECISION_EXACT));
		assertTrue(exactInvoked.get());
		assertEquals(7.0d, exact.rows());
	}

	@Test
	void repeatedQuadVariablesBecomeOneCanonicalEqualityProbe() {
		StatementPattern repeated = new StatementPattern(new Var("node"), new Var("p", P1), new Var("node"),
				new Var("graph"));
		QuadProbe probe = LmdbStorageEstimatorEvidence.probe(repeated,
				EstimateContext.root(repeated, IDENTITY, 4L));

		assertTrue(probe.isBound(QuadProbe.PREDICATE));
		assertTrue(probe.hasEqualityConstraints());
		assertEquals(probe.subjectId(), probe.objectId());
		assertEquals(QuadProbe.SUBJECT | QuadProbe.OBJECT | QuadProbe.CONTEXT, probe.projectedMask());
	}

	private static StatementPattern pattern(String subject, IRI predicate, String object) {
		return new StatementPattern(new Var(subject), new Var("p", predicate), new Var(object));
	}

	private static class RecordingEvidenceSource implements LmdbEstimatorEvidenceSource {
		private Set<String> boundNamesSeenForP2 = Set.of();
		private double prefixRowsSeenForP2;

		@Override
		public List<EstimateCandidate> leafCandidates(TupleExpr expression, EstimateContext context) {
			if (!(expression instanceof StatementPattern pattern)) {
				return List.of();
			}
			if (P2.equals(pattern.getPredicateVar().getValue())) {
				boundNamesSeenForP2 = context.boundNames();
				prefixRowsSeenForP2 = context.prefixEstimate().rows();
			}
			BagEstimate bag = bag(pattern);
			return List.of(new EstimateCandidate(bag,
					new RowEvidence(bag.rows(), bag.rows(), bag.rows(), 1.0d, true, IDENTITY, 4L,
							"exact_storage"),
					EstimateCandidate.Kind.EXACT_STORAGE, 1L));
		}

		@Override
		public Optional<FilterEvidence> filterEvidence(TupleExpr input, org.eclipse.rdf4j.query.algebra.ValueExpr condition,
				BagEstimate inputEstimate, EstimateContext context) {
			return Optional.of(new FilterEvidence(0.5d, 0.5d, 0.5d, 1.0d, true, "exact-filter"));
		}

		private BagEstimate bag(StatementPattern pattern) {
			Map<String, VariableEstimate> variables = new LinkedHashMap<>();
			if (P1.equals(pattern.getPredicateVar().getValue())) {
				variables.put(pattern.getSubjectVar().getName(), VariableEstimate.bound(4.0d, 2.0d));
				variables.put(pattern.getObjectVar().getName(), VariableEstimate.bound(4.0d, 4.0d));
			} else {
				variables.put(pattern.getSubjectVar().getName(), VariableEstimate.bound(4.0d, 4.0d));
				variables.put(pattern.getObjectVar().getName(), VariableEstimate.bound(4.0d, 2.0d));
			}
			return new BagEstimate(4.0d, 4.0d, 0.0d, 1.0d, "exact_storage", variables, Map.of(), Map.of());
		}
	}
